import azure.functions as func
import logging
import json
import os
from azure.identity import DefaultAzureCredential
from azure.storage.blob import BlobServiceClient
from azure.cosmos import CosmosClient
from azure.eventgrid import EventGridPublisherClient
from azure.core.messaging import CloudEvent
from datetime import datetime
import uuid

app = func.FunctionApp()

# Configuration
STORAGE_ACCOUNT_URL = os.environ.get("STORAGE_ACCOUNT_URL", "https://<storage-account>.blob.core.windows.net")
COSMOS_ENDPOINT = os.environ.get("COSMOS_ENDPOINT", "https://<cosmos-account>.documents.azure.com:443/")
COSMOS_DATABASE = os.environ.get("COSMOS_DATABASE", "ProcessedData")
COSMOS_CONTAINER = os.environ.get("COSMOS_CONTAINER", "Results")
EVENT_GRID_ENDPOINT = os.environ.get("EVENT_GRID_ENDPOINT", "https://<topic-name>.<region>.eventgrid.azure.net/api/events")

# Initialize clients with Managed Identity
credential = DefaultAzureCredential()
blob_service_client = BlobServiceClient(account_url=STORAGE_ACCOUNT_URL, credential=credential)
cosmos_client = CosmosClient(url=COSMOS_ENDPOINT, credential=credential)
event_grid_client = EventGridPublisherClient(EVENT_GRID_ENDPOINT, credential)

# Get Cosmos DB database and container
database = cosmos_client.get_database_client(COSMOS_DATABASE)
container = database.get_container_client(COSMOS_CONTAINER)


@app.blob_trigger(arg_name="myblob", path="input-files/{name}",
                  connection="STORAGE_ACCOUNT_URL")
def process_blob_file(myblob: func.InputStream):
    logging.info(f"Processing blob: {myblob.name}, Size: {myblob.length} bytes")
    
    try:
        # Read blob content
        blob_content = myblob.read()
        
        # Process the file (example: parse JSON or text)
        processed_data = process_file_content(blob_content, myblob.name)
        
        # Write results to Cosmos DB
        cosmos_result = write_to_cosmos(processed_data)
        logging.info(f"Written to Cosmos DB with id: {cosmos_result['id']}")
        
        # Send notification via Event Grid
        send_event_grid_notification(myblob.name, cosmos_result['id'], "success")
        logging.info(f"Event Grid notification sent for {myblob.name}")
        
        # Optionally move processed file to archive container
        archive_blob(myblob.name)
        
    except Exception as e:
        logging.error(f"Error processing blob {myblob.name}: {str(e)}")
        send_event_grid_notification(myblob.name, None, "failed", str(e))
        raise


def process_file_content(content: bytes, filename: str) -> dict:
    """Process the file content and return structured data"""
    try:
        # Try to parse as JSON
        data = json.loads(content.decode('utf-8'))
        processed = {
            "filename": filename,
            "content_type": "json",
            "data": data,
            "record_count": len(data) if isinstance(data, list) else 1
        }
    except json.JSONDecodeError:
        # Handle as text file
        text_content = content.decode('utf-8')
        lines = text_content.split('\n')
        processed = {
            "filename": filename,
            "content_type": "text",
            "line_count": len(lines),
            "preview": lines[:5] if len(lines) > 5 else lines,
            "total_characters": len(text_content)
        }
    except Exception:
        # Handle as binary
        processed = {
            "filename": filename,
            "content_type": "binary",
            "size_bytes": len(content)
        }
    
    processed["processed_at"] = datetime.utcnow().isoformat()
    processed["id"] = str(uuid.uuid4())
    
    return processed


def write_to_cosmos(data: dict) -> dict:
    """Write processed data to Cosmos DB"""
    # Add partition key if needed
    if "partition_key" not in data:
        data["partition_key"] = data.get("filename", "default")
    
    # Upsert the document
    result = container.upsert_item(body=data)
    return result


def send_event_grid_notification(filename: str, cosmos_id: str, status: str, error_message: str = None):
    """Send notification to Event Grid"""
    event_data = {
        "filename": filename,
        "cosmos_id": cosmos_id,
        "status": status,
        "timestamp": datetime.utcnow().isoformat()
    }
    
    if error_message:
        event_data["error"] = error_message
    
    event = CloudEvent(
        type="BlobProcessing.FileProcessed",
        source="azure-function-blob-processor",
        data=event_data,
        subject=f"files/{filename}"
    )
    
    event_grid_client.send([event])


def archive_blob(blob_name: str):
    """Move processed blob to archive container"""
    try:
        # Extract container and blob path
        parts = blob_name.split('/', 1)
        if len(parts) == 2:
            source_container = parts[0]
            blob_path = parts[1]
        else:
            source_container = "input-files"
            blob_path = blob_name
        
        # Get source and destination clients
        source_blob_client = blob_service_client.get_blob_client(
            container=source_container, 
            blob=blob_path
        )
        
        archive_container_client = blob_service_client.get_container_client("archive")
        
        # Create archive container if it doesn't exist
        try:
            archive_container_client.create_container()
        except Exception:
            pass  # Container already exists
        
        # Copy to archive
        archive_blob_name = f"{datetime.utcnow().strftime('%Y/%m/%d')}/{blob_path}"
        archive_blob_client = blob_service_client.get_blob_client(
            container="archive",
            blob=archive_blob_name
        )
        
        archive_blob_client.start_copy_from_url(source_blob_client.url)
        
        # Delete original (optional - comment out if you want to keep originals)
        # source_blob_client.delete_blob()
        
        logging.info(f"Archived blob to: archive/{archive_blob_name}")
        
    except Exception as e:
        logging.warning(f"Failed to archive blob {blob_name}: {str(e)}")


@app.route(route="health", methods=["GET"])
def health_check(req: func.HttpRequest) -> func.HttpResponse:
    """Health check endpoint"""
    return func.HttpResponse(
        json.dumps({"status": "healthy", "timestamp": datetime.utcnow().isoformat()}),
        mimetype="application/json",
        status_code=200
    )


@app.route(route="query", methods=["GET", "POST"])
def query_cosmos(req: func.HttpRequest) -> func.HttpResponse:
    """Query Cosmos DB for processed files"""
    try:
        # Get query parameters
        filename = req.params.get('filename')
        limit = int(req.params.get('limit', 10))
        
        if filename:
            query = f"SELECT * FROM c WHERE c.filename = @filename"
            parameters = [{"name": "@filename", "value": filename}]
        else:
            query = f"SELECT TOP {limit} * FROM c ORDER BY c.processed_at DESC"
            parameters = None
        
        items = list(container.query_items(
            query=query,
            parameters=parameters,
            enable_cross_partition_query=True
        ))
        
        return func.HttpResponse(
            json.dumps(items, indent=2),
            mimetype="application/json",
            status_code=200
        )
        
    except Exception as e:
        logging.error(f"Error querying Cosmos DB: {str(e)}")
        return func.HttpResponse(
            json.dumps({"error": str(e)}),
            mimetype="application/json",
            status_code=500
        )


@app.route(route="reprocess", methods=["POST"])
def reprocess_file(req: func.HttpRequest) -> func.HttpResponse:
    """Manually trigger reprocessing of a file"""
    try:
        req_body = req.get_json()
        container_name = req_body.get('container', 'input-files')
        blob_name = req_body.get('blob_name')
        
        if not blob_name:
            return func.HttpResponse(
                json.dumps({"error": "blob_name is required"}),
                mimetype="application/json",
                status_code=400
            )
        
        # Get blob client
        blob_client = blob_service_client.get_blob_client(
            container=container_name,
            blob=blob_name
        )
        
        # Download and process
        blob_data = blob_client.download_blob().readall()
        processed_data = process_file_content(blob_data, blob_name)
        cosmos_result = write_to_cosmos(processed_data)
        send_event_grid_notification(blob_name, cosmos_result['id'], "reprocessed")
        
        return func.HttpResponse(
            json.dumps({"status": "success", "cosmos_id": cosmos_result['id']}),
            mimetype="application/json",
            status_code=200
        )
        
    except Exception as e:
        logging.error(f"Error reprocessing file: {str(e)}")
        return func.HttpResponse(
            json.dumps({"error": str(e)}),
            mimetype="application/json",
            status_code=500
        )